// Generates js/standalone-source.js — a snapshot of play.html with every
// `<script src="js/…">` replaced by its inlined content. editor.html's
// "Export Game" flow patches EMBEDDED_PRG / EMBEDDED_D64 (both null in
// the snapshot) with the current program's base64-encoded PRG + D64,
// producing a fully self-contained playable HTML file.
//
// This bundle is why the exported player is *literally* play.html with
// two consts populated — a single source of truth means any change to
// play.html lands in the exported HTML too, automatically.
//
// Why bundle at build time (rather than reading play.html at Export click):
// file:// blocks fetch() in every modern browser, so the Export can't load
// play.html at click time when the editor was opened directly. Bundling
// as a regular <script>-loadable JS file sidesteps that — script tags
// work fine from file://.
//
// Re-run after editing play.html or any of the JS files it loads:
//     node tools/bundle-standalone.js
// (Test suite verifies the bundle is current; see
// tests/standalone-bundle.test.js.)

import { readFileSync, writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const ROOT = resolve(__dirname, '..');

const HEADER = `// This file is generated by tools/bundle-standalone.js.
// DO NOT EDIT — re-run \`node tools/bundle-standalone.js\` after changing
// play.html or any of the JS files it loads. The test suite verifies
// this bundle is current.
//
// Provides window._standaloneSource — a snapshot of play.html with every
// <script src="js/…"> replaced by an inlined script block. editor.html's
// Export Game flow patches EMBEDDED_PRG / EMBEDDED_D64 (both null in the
// snapshot) with base64-encoded game bytes to produce a self-contained
// playable HTML file.
`;

export function generate() {
    let playHtml = readFileSync(resolve(ROOT, 'play.html'), 'utf8');

    // Strip sections wrapped in `<!-- bundle:exclude -->…<!-- /bundle:exclude -->`.
    // Used for things that belong on the hosted site (e.g. telemetry) but
    // shouldn't ship in exported standalone games. Runs BEFORE script
    // inlining so the excluded <script src=...> tags never get resolved.
    playHtml = playHtml.replace(
        /<!--\s*bundle:exclude\s*-->[\s\S]*?<!--\s*\/bundle:exclude\s*-->/g,
        ''
    );

    // Match only the self-contained form: `<script src="js/…"></script>`
    // (no body, single-line, points at a local JS path). Every remaining
    // include in play.html matches this shape — bail loudly if that ever
    // stops being true, since silently missing a tag would break exports.
    const inlined = playHtml.replace(
        /<script\s+src="(js\/[^"]+)"><\/script>/g,
        (_match, path) => {
            const contents = readFileSync(resolve(ROOT, path), 'utf8');
            // No `</script>` scrub needed — none of the runtime JS
            // contains that literal (the test suite guards against
            // regressions).
            return `<script>${contents}</script>`;
        }
    );

    return HEADER + `window._standaloneSource = ${JSON.stringify(inlined)};\n`;
}

// CLI: write the bundle to disk.
if (import.meta.url === `file://${process.argv[1]}`) {
    const out = generate();
    const target = resolve(ROOT, 'js', 'standalone-source.js');
    writeFileSync(target, out);
    console.log(`wrote ${target} (${out.length.toLocaleString()} bytes)`);
}
